sql:
SELECT SUM(daily_rainfall_total_mm) AS total_rainfall
FROM daily_weather_data
WHERE station_id = 1 AND data_date BETWEEN '1985-01-01' AND '1985-01-31';

SELECT data_date, daily_rainfall_total_mm
FROM daily_weather_data
WHERE daily_rainfall_total_mm > 0.0;

SELECT data_date, mean_temperature_c, max_temperature_c
FROM daily_weather_data
WHERE mean_temperature_c = (SELECT MAX(mean_temperature_c) FROM daily_weather_data);

SELECT highest_30_min_rainfall_mm
FROM daily_weather_data
WHERE data_id = 0;

SELECT maintenance_type, maintenance_duration_minutes
FROM station_maintenance
ORDER BY maintenance_duration_minutes DESC;

SELECT MAX(max_temperature_c) AS max_temperature
FROM daily_weather_data
WHERE station_id = (SELECT station_id FROM weather_stations WHERE station_name = 'Changi');
